import React, { useState, useRef, useEffect } from 'react';
import { Search, X, Filter, Grid, List } from 'lucide-react';
import { useDebounce } from '../hooks/useDebounce';

const UnifiedSearch = ({ onSearch, onFilter, onSort, onViewChange, viewMode, className = "" }) => {
  const [query, setQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filters, setFilters] = useState({ category: 'all', priceRange: [0, 200], rating: 0 });
  const inputRef = useRef(null);

  const debouncedQuery = useDebounce(query, 300);

  useEffect(() => {
    onSearch(debouncedQuery);
  }, [debouncedQuery, onSearch]);

  const handleFilterChange = (key, value) => {
    const newFilters = { ...filters, [key]: value };
    setFilters(newFilters);
    onFilter(newFilters);
  };

  const clearAll = () => {
    setQuery('');
    setFilters({ category: 'all', priceRange: [0, 200], rating: 0 });
    onSearch('');
    onFilter({ category: 'all', priceRange: [0, 200], rating: 0 });
  };

  return (
    <div className={`bg-white border-b border-gray-200 py-6 ${className}`}>
      <div className="max-w-7xl mx-auto px-4">
        <div className="flex flex-col lg:flex-row gap-4 items-center">
          {/* Search Bar */}
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input ref={inputRef} type="text" value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search courses..." className="w-full pl-10 pr-10 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent" />
            {query && (
              <button onClick={() => setQuery('')} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600">
                <X className="w-5 h-5" />
              </button>
            )}
          </div>

          {/* Category Filters */}
          <div className="flex flex-wrap gap-2">
            {['all', 'development', 'ai', 'design', 'business'].map(cat => (
              <button key={cat} onClick={() => handleFilterChange('category', cat)} className={`px-4 py-2 rounded-xl text-sm font-medium transition-all ${filters.category === cat ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}>
                {cat === 'all' ? 'All' : cat === 'ai' ? 'AI & ML' : cat.charAt(0).toUpperCase() + cat.slice(1)}
              </button>
            ))}
          </div>

          {/* Controls */}
          <div className="flex items-center gap-2">
            <button onClick={() => setShowFilters(!showFilters)} className="flex items-center px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-xl hover:bg-gray-200">
              <Filter className="w-4 h-4 mr-2" />Advanced
            </button>

            <select onChange={(e) => onSort(e.target.value)} className="px-4 py-2 border border-gray-300 rounded-xl text-sm focus:ring-2 focus:ring-blue-500">
              <option value="rating">⭐ Highest Rated</option>
              <option value="price">💰 Price: Low to High</option>
              <option value="enrolled">🔥 Most Popular</option>
            </select>

            <div className="flex bg-gray-100 rounded-xl p-1">
              <button onClick={() => onViewChange('grid')} className={`p-2 rounded-lg ${viewMode === 'grid' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-600'}`}>
                <Grid className="w-4 h-4" />
              </button>
              <button onClick={() => onViewChange('list')} className={`p-2 rounded-lg ${viewMode === 'list' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-600'}`}>
                <List className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>

        {/* Advanced Filters */}
        {showFilters && (
          <div className="mt-6 p-6 bg-gray-50 rounded-2xl">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Price Range: ₹0 - ₹{filters.priceRange[1]}</label>
                <input type="range" min="0" max="200" value={filters.priceRange[1]} onChange={(e) => handleFilterChange('priceRange', [0, parseInt(e.target.value)])} className="w-full" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Minimum Rating</label>
                <select value={filters.rating} onChange={(e) => handleFilterChange('rating', parseFloat(e.target.value))} className="w-full border border-gray-300 rounded-lg px-3 py-2">
                  <option value={0}>Any Rating</option>
                  <option value={4.5}>4.5+ Stars</option>
                  <option value={4.0}>4.0+ Stars</option>
                  <option value={3.5}>3.5+ Stars</option>
                </select>
              </div>
            </div>
            <button onClick={clearAll} className="mt-4 px-4 py-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200 transition-colors">
              Clear All Filters
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default UnifiedSearch;
